// ✅ AO 프롬프트 조립기 — P1 원문 100% 보존
const job = $input.first().json;

// P1 원문은 절대 변경 금지
const p1 = job.prompt_p1;
if (!p1) throw new Error('P1 원문 없음 — 작업 중단');

// 이미지 슬롯 파싱
let imageSlots = {};
try {
  imageSlots = typeof job.image_slots === 'string'
    ? JSON.parse(job.image_slots)
    : (job.image_slots || {});
} catch(e) {
  imageSlots = {};
}

// 슬롯 값 준비 (없으면 빈 문자열)
const slotValues = {
  TOPIC: job.topic || '',
  KEYWORDS: job.keywords || '',
  CATEGORY: job.category || '',
  IMG_1: imageSlots.IMG_1 || '',
  IMG_2: imageSlots.IMG_2 || '',
  IMG_3: imageSlots.IMG_3 || '',
  IMG_4: imageSlots.IMG_4 || '',
  REF_VIDEO: job.ref_video || '',
  LANG: job.prompt_lang_detected || 'ko',
  ASPECT_RATIO: '9:16'
};

// 누락 슬롯 로그 수집
const missedSlots = Object.entries(slotValues)
  .filter(([k, v]) => !v)
  .map(([k]) => k);

// 최종 프롬프트: P1 그대로 + 슬롯 주입
const finalPrompt = p1
  .replace(/\{TOPIC\}/g, slotValues.TOPIC)
  .replace(/\{KEYWORDS\}/g, slotValues.KEYWORDS)
  .replace(/\{CATEGORY\}/g, slotValues.CATEGORY)
  .replace(/\{IMG_1\}/g, slotValues.IMG_1)
  .replace(/\{IMG_2\}/g, slotValues.IMG_2)
  .replace(/\{IMG_3\}/g, slotValues.IMG_3)
  .replace(/\{IMG_4\}/g, slotValues.IMG_4)
  .replace(/\{REF_VIDEO\}/g, slotValues.REF_VIDEO)
  .replace(/\{LANG\}/g, slotValues.LANG)
  .replace(/\{ASPECT_RATIO\}/g, slotValues.ASPECT_RATIO);

return [{
  json: {
    ...job,
    prompt_to_engine: finalPrompt,
    prompt_p1_preserved: p1,  // 원문 보존 확인용
    missed_slots: missedSlots,
    assembled_at: new Date().toISOString()
  }
}];

