const prev = $('번역 필요 여부').first().json;
const translated = $input.first().json;

const promptEn = translated.content?.[0]?.text || prev.prompt_to_engine;

return [{
  json: {
    ...prev,
    prompt_en: promptEn
  }
}];

// Replicate 폴링 — 완료될 때까지 대기
const predictionId = $input.first().json.id;
const apiKey = $credentials?.httpHeaderAuth?.value || '';

let status = 'starting';
let output = null;
let attempts = 0;
const maxAttempts = 30;

while (!['succeeded', 'failed', 'canceled'].includes(status) && attempts < maxAttempts) {
  await new Promise(r => setTimeout(r, 3000));
  const resp = await fetch(`https://api.replicate.com/v1/predictions/${predictionId}`, {
    headers: { 'Authorization': `Bearer ${apiKey}` }
  });
  const data = await resp.json();
  status = data.status;
  output = data.output;
  attempts++;
}

if (status !== 'succeeded' || !output) {
  throw new Error(`이미지 생성 실패: ${status}`);
}

const prev = $('이미지 생성 필요 여부').first().json;
return [{
  json: {
    ...prev,
    generated_images: Array.isArray(output) ? output : [output]
  }
}];

// Creatomate 렌더 폴링
const renderId = $input.first().json.id || $input.first().json[0]?.id;
const apiKey = '';

let status = 'planned';
let url = null;
let attempts = 0;
const maxAttempts = 60;

while (!['succeeded', 'failed'].includes(status) && attempts < maxAttempts) {
  await new Promise(r => setTimeout(r, 5000));
  const resp = await fetch(`https://api.creatomate.com/v1/renders/${renderId}`, {
    headers: { 'Authorization': `Bearer ${apiKey}` }
  });
  const data = await resp.json();
  status = data.status;
  url = data.url;
  attempts++;
}

if (status !== 'succeeded' || !url) {
  throw new Error(`영상 렌더링 실패: ${status}`);
}

const prev = $('영상 렌더링 (Creatomate)').first().json;
return [{
  json: {
    ...prev,
    rendered_video_url: url,
    render_id: renderId
  }
}];

// ✅ 에러 핸들러 — 재시도 로직
const error = $input.first().json;
const jobId = $('큐에서 Job 꺼내기').first().json?.id;

if (!jobId) return [];

return [{
  json: {
    job_id: jobId,
    error_message: error.message || JSON.stringify(error),
    timestamp: new Date().toISOString()
  }
}];
